// // This is a 4-bit down-counter that counts from 15 to 0 and then wraps around.
module counter_4bit(
    input clk, reset,
    output reg [3:0] count);

    always @(posedge clk) begin
        if (reset)
            count <= 4'b0;
        else
            count <= count + 1;
    end
endmodule
